#include<bits/stdc++.h>
using namespace std;
int pre[100010];
unordered_map<string,int> mp;
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        string s;
        cin>>s;
        mp[s]=i;
    }
    int m;
    scanf("%d",&m);
    set<int> s;
    int ans=0,max1=0;
    for(int i=1;i<=m;i++)
    {
        string str;
        cin>>str;
        if(!mp[str])
        {
            continue;
        }
        int tmp=mp[str];
        if(pre[tmp])
        {
            s.erase(s.lower_bound(pre[tmp]));
        }
        pre[tmp]=i;
        s.insert(i);
        if(s.size()>max1)
        {
            max1=s.size();
            ans=(i-(*s.begin())+1);
        }
        else if(s.size()==max1&&ans>(i-(*s.begin())+1))
        {
            ans=(i-(*s.begin())+1);
        }
    }
    printf("%d\n%d",max1,ans);
    return 0;
}
